def ensure_general_business_knowledge(db: Any) -> bool:
    """Add a large offline general/business knowledge pack once.

    It is educational base knowledge, not live tax/legal/financial advice.
    Existing user data and learned data are preserved.
    """
    title = "M0N4C0 Seed Knowledge: General Business Money Tax Brain Pack"
    source_id: int | None = None
    try:
        with db.connect() as conn:
            row = conn.execute("SELECT id FROM knowledge_sources WHERE title=? LIMIT 1", (title,)).fetchone()
            if row:
                source_id = int(row["id"])
    except Exception:
        return False
    if source_id is None:
        source_id = db.add_source(
            "seed",
            title,
            None,
            "General Business Knowledge",
            metadata={"created_for": "M0N4C0 general knowledge", "level": "expert", "offline_seed": True, "advice_scope": "educational"},
            reliability=0.80,
        )
    written = 0
    all_items = GENERAL_BUSINESS_KNOWLEDGE + EXTRA_GENERAL_BUSINESS_KNOWLEDGE
    for idx, item in enumerate(all_items):
        if db.add_chunk(
            source_id=source_id,
            topic=item["topic"],
            title=item["title"],
            url=None,
            chunk_index=idx,
            content=item["content"],
            summary=item["summary"],
            keywords=item["keywords"],
            quality_score=0.82,
        ):
            written += 1
    for subject, predicate, obj in GENERAL_BUSINESS_FACTS:
        db.add_memory_fact(subject, predicate, obj, source="general_business_seed", confidence=0.84)
    return written > 0
